import requestsimport osimport jsonfrom core.config import GROQ_API_KEY, GEMINI_API_KEYfrom core.memory_store import LintMemoryStoreclass LintLLMClient:    MEMORY_PREVIEW_CHARS = 600    def __init__(self):        self.groq_key = GROQ_API_KEY        self.gemini_key = GEMINI_API_KEY        self.memory = LintMemoryStore()        self.system_prompt = ("your prompt here this is personality and instructions for the agent.")    def ask_cat(self, query: str, context: str = "", model_override: str = None, temp=0.7) -> str:        # Default fallback model strategy        active_model = model_override if model_override else "llama-3.3-70b-versatile"        resolved_memory_context = self.memory.get_context()        memory_block = f"memory: {resolved_memory_context}\n\n" if resolved_memory_context else ""        user_payload = f"context: {context}\n\n{memory_block}query: {query}"        # ROUTE A: Use Groq for lightweight tasks        if "llama" in active_model or "mixtral" in active_model:            if not self.groq_key:                return "Error: GROQ API key is unconfigured."            # FIXED: Corrected URL to valid chat completions endpoint            url = "https://api.groq.com/openai/v1/chat/completions"            headers = {"Authorization": f"Bearer {self.groq_key}", "Content-Type": "application/json"}            body = {                "model": active_model,                "messages": [                    {"role": "system", "content": self.system_prompt},                    {"role": "user", "content": user_payload}                ],                "temperature": temp            }            try:                resp = requests.post(url, headers=headers, json=body, timeout=10.0)                if resp.status_code == 429:                    return "Error: Groq rate limit reached."                if resp.status_code == 200:                    # FIXED: Removed .lower() which corrupts code/JSON capitalization structural integrity                    reply = resp.json()["choices"][0]["message"]["content"].strip()                    self.memory.add_entry("chat", query, reply, {"model": active_model, "provider": "groq"})                    return reply                return f"Error: Groq API returned status code {resp.status_code}."            except Exception:                return "Error: Communication with Groq gateway failed."        # ROUTE B: Use Gemini for Heavy Workspace Contexts        else:            if not self.gemini_key:                return "Error: Gemini API key is unconfigured."            # Map legacy overrides if requested by agent systems            gemini_model_id = "gemini-2.5-flash"            if model_override and "gemini-2.0" in model_override:                gemini_model_id = "gemini-2.0-flash"            # FIXED: Corrected structural URL endpoint formatting            url = f"https://generativelanguage.googleapis.com/v1beta/models/{gemini_model_id}:generateContent?key={self.gemini_key}"            # CRITICAL ENFORCEMENT PROTOCOL: Appends absolute rule to suppress yapping and force file mutations            sandbox_enforcer = (                "\n\nCRITICAL ENFORCEMENT PROTOCOL:\n"                "1. DO NOT give chat advice or tell the user to manually run commands like pip install.\n"                "2. If a dependency or fix is needed, you MUST apply it directly by writing the code change "                "inside the 'mutations' JSON object (e.g., updating a requirements.txt, setup.py, or adding error handling imports).\n"                "3. Keep the 'summary' extremely short, technical, and free of personality or commentary."            )            body = {                "contents": [                    {"role": "user", "parts": [{"text": f"{self.system_prompt}{sandbox_enforcer}\n\n{user_payload}"}]}                ]            }            try:                resp = requests.post(url, headers={"Content-Type": "application/json"}, json=body, timeout=60.0)                if resp.status_code == 200:                    reply = resp.json()["candidates"][0]["content"]["parts"][0]["text"].strip()                    self.memory.add_entry("chat", query, reply, {"model": gemini_model_id, "provider": "gemini"})                    return reply                return f"Error: Gemini API returned status code {resp.status_code} - {resp.text}."            except Exception as e:                return f"Error: Gemini routing connection timed out or failed: {str(e)}"    def run_multi_file_agent(self, instruction: str) -> str:        if not self.gemini_key:            return "Error: Gemini API key is required to modify workspace files."        # Build Snapshot map        project_files = {}        for root, _, files in os.walk("."):            if any(p in root for p in [".git", "__pycache__", ".venv", ".idea"]):                continue            for file in files:                if file.endswith((".py", ".txt", ".json", ".md", ".env", ".bat")):                    rel = os.path.relpath(os.path.join(root, file), ".")                    try:                        with open(rel, "r", encoding="utf-8") as f:                            project_files[rel] = f.read()                    except:                        pass        ctx = ""        for p, b in project_files.items():            ctx += f"--- PATH: {p} ---\n{b}\n\n"        memory_context = self.memory.get_context()        prompt = (            f"Update these files based on instructions: {instruction}. "            f"Respond ONLY with a raw parseable json dictionary mapping file paths to their exact complete new string contents. "            f"Do not include markdown codeblock wrappers formatting."        )        # FIXED: Corrected complete endpoint string context for multi-file routines        url = f"https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key={self.gemini_key}"        try:            resp = requests.post(url, headers={"Content-Type": "application/json"}, json={                "contents": [{                    "role": "user",                    "parts": [{                                  "text": f"{prompt}\n\nShared Memory:\n{memory_context}\n\nWorkspace System File Context:\n{ctx}"}]                }]            }, timeout=30.0)            if resp.status_code != 200:                return f"Error: HTTP {resp.status_code} - {resp.text}"            raw = resp.json()["candidates"][0]["content"]["parts"][0]["text"].strip()            if raw.startswith("```"):                raw = "\n".join(raw.splitlines()[1:-1]) if raw.splitlines()[0].startswith("```") else raw            mutations = json.loads(raw)            for filepath, content in mutations.items():                os.makedirs(os.path.dirname(os.path.abspath(filepath)), exist_ok=True)                with open(filepath, "w", encoding="utf-8") as f:                    f.write(content.strip())            self.memory.add_entry("modify", instruction, f"modified {len(mutations)} files",                                  {"files": list(mutations.keys())[:20]})            return f"Success: Modified {len(mutations)} codebase targets."        except Exception as e:            return f"Error: Agent execution loop broken: {str(e)}"    def memory_clear(self) -> str:        self.memory.clear()        return "Success: Local memory buffer wiped clean."    def memory_show(self) -> str:        details = self.memory.describe()        preview = self.memory.get_context()        if not preview:            return details        return f"{details}\n{preview[-self.MEMORY_PREVIEW_CHARS:]}"